import { useState, useEffect } from 'react';
import { useParams, useNavigate, useOutletContext } from 'react-router-dom';
import {
    Card,
    Button,
    Table,
    Modal,
    Form,
    Input,
    InputNumber,
    message,
    Tag,
    Space,
    Select,
    Progress,
    Upload,
    Row,
    Col,
} from 'antd';
import {
    ArrowLeftOutlined,
    PlusOutlined, // Added
    EditOutlined,
    FileTextOutlined,
    UploadOutlined,
    ClockCircleOutlined,
    SafetyCertificateOutlined,
    QuestionCircleOutlined,
    PlusCircleOutlined,
    BookOutlined,
    CheckCircleOutlined,
    EyeOutlined,
    LockOutlined,
    UnlockOutlined,
    EyeInvisibleOutlined,
    DeleteOutlined,
} from '@ant-design/icons';
import type { ColumnsType } from 'antd/es/table';
import { testApi, partApi, uploadApi } from '../services/api';
import InstructionEditor from '../components/InstructionEditor';

const { Option } = Select;

interface Test {
    id: string;
    title: string;
    testType: 'LISTENING' | 'READING';
    difficulty: 'A1_A2' | 'B1_B2' | 'C1';
    status: 'PENDING' | 'ACTIVE' | 'LOCKED' | 'REJECTED';
    rejectReason?: string;
    duration: number;
    totalQuestions: number;
    createdAt: string;
    updatedAt: string;
}

interface Part {
    id: string;
    testId: string;
    partNumber: number;
    partName: string;
    totalQuestions: number;
    instructions?: string;
    instructionImgUrl?: string;
    status: 'PENDING' | 'ACTIVE' | 'LOCKED' | 'REJECTED';
    rejectReason?: string;
    orderIndex: number;
    completedQuestions: number;
    createdAt: string;
    updatedAt: string;
    timeLimit?: number; // in seconds
    audioUrl?: string;
}

// Auto-fill configuration for parts
const PART_CONFIG: Record<number, { name: string; totalQuestions: number; timeLimit: number }> = {
    1: { name: 'Part 1: Photographs', totalQuestions: 6, timeLimit: 300 }, // 5 mins
    2: { name: 'Part 2: Question-Response', totalQuestions: 25, timeLimit: 480 }, // 8 mins
    3: { name: 'Part 3: Conversations', totalQuestions: 39, timeLimit: 1020 }, // 17 mins
    4: { name: 'Part 4: Talks', totalQuestions: 30, timeLimit: 900 }, // 15 mins
    5: { name: 'Part 5: Incomplete Sentences', totalQuestions: 30, timeLimit: 600 }, // 10 mins
    6: { name: 'Part 6: Text Completion', totalQuestions: 16, timeLimit: 480 }, // 8 mins
    7: { name: 'Part 7: Reading Comprehension', totalQuestions: 54, timeLimit: 3240 }, // 54 mins
};

export default function TestDetail() {
    const { user } = useOutletContext<{ user: any }>();
    const isAdmin = user?.role === 'ADMIN';
    const isSpecialist = user?.role === 'SPECIALIST';
    // const isTeacher = user?.role === 'TEACHER';
    const canManage = isAdmin || isSpecialist;

    const { testId } = useParams<{ testId: string }>();
    const navigate = useNavigate();
    const [test, setTest] = useState<Test | null>(null);
    const [parts, setParts] = useState<Part[]>([]);
    const [loading, setLoading] = useState(false);
    const [createModalVisible, setCreateModalVisible] = useState(false);
    const [editModalVisible, setEditModalVisible] = useState(false);
    const [editingPart, setEditingPart] = useState<Part | null>(null);
    const [form] = Form.useForm();
    const [createForm] = Form.useForm();

    // Cß║Ñu h├¼nh b├│ng ─æß╗ò hiß╗çn ─æß║íi
    const modernShadow = '0 10px 30px -5px rgba(37, 99, 235, 0.08), 0 4px 10px -6px rgba(37, 99, 235, 0.04)';

    const [createInstructions, setCreateInstructions] = useState('');
    const [editInstructions, setEditInstructions] = useState('');

    // Cascading Approval State - REMOVED handleApproveAll but keeping approving for individual actions
    const [approving, setApproving] = useState(false);

    // Rejection State
    const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
    const [rejectReason, setRejectReason] = useState('');
    const [rejecting, setRejecting] = useState(false);

    // Part Audio Edit State
    const [editPartAudioFileList, setEditPartAudioFileList] = useState<any[]>([]);

    useEffect(() => {
        if (testId) {
            fetchTest();
            fetchParts();
        }
    }, [testId]);

    const handleDeleteTest = async () => {
        if (!test) return;
        Modal.confirm({
            title: 'X├íc nhß║¡n x├│a ─æß╗ü thi',
            content: (
                <div>
                    <p>Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a ─æß╗ü thi <strong>"{test.title}"</strong>?</p>
                    <p style={{ color: '#DC2626', marginTop: 8 }}>
                        ΓÜá∩╕Å H├ánh ─æß╗Öng n├áy <strong>kh├┤ng thß╗â ho├án t├íc</strong>. To├án bß╗Ö c├óu hß╗Åi v├á dß╗» liß╗çu li├¬n quan sß║╜ bß╗ï x├│a v─⌐nh viß╗àn khß╗Åi Cloudinary v├á Database.
                    </p>
                </div>
            ),
            okText: 'X├│a v─⌐nh viß╗àn',
            okType: 'danger',
            cancelText: 'Hß╗ºy',
            onOk: async () => {
                try {
                    const data = await testApi.delete(testId!);
                    if (data.success) {
                        message.success('─É├ú x├│a ─æß╗ü thi th├ánh c├┤ng!');
                        navigate('/exam-bank');
                    } else {
                        message.error(data.message || 'Kh├┤ng thß╗â x├│a ─æß╗ü thi');
                    }
                } catch (error) {
                    console.error('Error deleting exam:', error);
                    message.error('C├│ lß╗ùi xß║úy ra khi x├│a ─æß╗ü thi');
                }
            },
        });
    };

    const fetchTest = async () => {
        try {
            const data = await testApi.getDetails(testId!);
            if (data.success) {
                setTest(data.test);
            }
        } catch (error) {
            console.error('Error fetching test details:', error);
        }
    };

    const fetchParts = async () => {
        setLoading(true);
        try {
            const data = await testApi.getParts(testId!);
            if (data.success) {
                setParts(data.parts || []);
            }
        } catch (error) {
            console.error('Error fetching parts:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleCreatePart = async (values: any) => {
        // Validate instructions
        if (!createInstructions || createInstructions.trim() === '') {
            message.error('Vui l├▓ng nhß║¡p h╞░ß╗¢ng dß║½n cho Part n├áy');
            return;
        }

        try {
            // Calculate timeLimit (minutes * 60 + seconds)
            const timeLimit = (values.timeLimitMinutes || 0) * 60 + (values.timeLimitSeconds || 0);

            const data = await partApi.create(testId!, {
                ...values,
                timeLimit,
                instructions: createInstructions,
            });

            // Remove temp fields
            delete (values as any).timeLimitHours;
            delete (values as any).timeLimitMinutes;
            delete (values as any).timeLimitSeconds;

            if (data.success) {
                message.success('Tß║ío Part th├ánh c├┤ng!');
                setCreateModalVisible(false);
                createForm.resetFields();
                setCreateInstructions('');
                fetchParts();
            } else {
                message.error(data.message || 'Kh├┤ng thß╗â tß║ío Part');
            }
        } catch (error) {
            message.error('C├│ lß╗ùi xß║úy ra khi tß║ío Part');
        }
    };

    const handleEdit = (part: Part) => {
        setEditingPart(part);
        setEditInstructions(part.instructions || '');

        // Initialize audio file list if part has audioUrl
        if (part.audioUrl) {
            setEditPartAudioFileList([{
                uid: '-1',
                name: '├ém thanh hiß╗çn tß║íi',
                status: 'done',
                url: part.audioUrl,
            }]);
        } else {
            setEditPartAudioFileList([]);
        }

        form.setFieldsValue({
            partNumber: part.partNumber,
            partName: part.partName,
            totalQuestions: part.totalQuestions,
            timeLimitMinutes: Math.floor((part.timeLimit || 0) / 60),
            timeLimitSeconds: (part.timeLimit || 0) % 60,
            orderIndex: part.orderIndex,
        });
        setEditModalVisible(true);
    };

    const handleUpdatePart = async (values: any) => {
        if (!editingPart) return;

        // Validate instructions
        if (!editInstructions || editInstructions.trim() === '') {
            message.error('Vui l├▓ng nhß║¡p h╞░ß╗¢ng dß║½n cho Part n├áy');
            return;
        }

        try {
            let infoAudioUrl = editingPart.audioUrl;

            // Handle Audio Upload if changed
            if (editPartAudioFileList.length > 0 && editPartAudioFileList[0].originFileObj) {
                const audioRes = await uploadApi.audio(editPartAudioFileList[0].originFileObj);
                if (audioRes.success) {
                    infoAudioUrl = audioRes.url;
                } else {
                    message.error('Upload audio thß║Ñt bß║íi');
                    return;
                }
            } else if (editPartAudioFileList.length === 0) {
                infoAudioUrl = ''; // Removed audio
            }

            // Calculate timeLimit (minutes * 60 + seconds)
            const timeLimit = (values.timeLimitMinutes || 0) * 60 + (values.timeLimitSeconds || 0);

            const data = await partApi.update(editingPart.id, {
                ...values,
                timeLimit,
                instructions: editInstructions,
                audioUrl: infoAudioUrl,
            });

            // Remove temp fields
            delete (values as any).timeLimitHours;
            delete (values as any).timeLimitMinutes;
            delete (values as any).timeLimitSeconds;

            if (data.success) {
                message.success('Cß║¡p nhß║¡t Part th├ánh c├┤ng!');
                setEditModalVisible(false);
                setEditingPart(null);
                setEditInstructions('');
                form.resetFields();
                fetchParts();
            } else {
                message.error(data.message || 'Kh├┤ng thß╗â cß║¡p nhß║¡t Part');
            }
        } catch (error) {
            message.error('C├│ lß╗ùi xß║úy ra khi cß║¡p nhß║¡t Part');
        }
    };

    const handleViewDetails = (part: Part) => {
        navigate(`/exam-bank/${testId}/parts/${part.id}`);
    };



    const handleApproveTest = async () => {
        if (!test) return;

        Modal.confirm({
            title: 'X├íc nhß║¡n duyß╗çt ─æß╗ü thi',
            content: `Bß║ín c├│ chß║»c chß║»n muß╗æn duyß╗çt v├á xuß║Ñt bß║ún ─æß╗ü thi "${test.title}"? To├án bß╗Ö c├íc phß║ºn thi v├á c├óu hß╗Åi b├¬n trong sß║╜ ─æ╞░ß╗úc k├¡ch hoß║ít ─æß╗â hß╗ìc vi├¬n l├ám b├ái.`,
            okText: 'Duyß╗çt to├án bß╗Ö',
            okType: 'primary',
            onOk: async () => {
                setApproving(true);
                try {
                    const data = await testApi.approveFull(test.id);
                    if (data.success) {
                        message.success('─É├ú duyß╗çt v├á xuß║Ñt bß║ún to├án bß╗Ö ─æß╗ü thi th├ánh c├┤ng!');
                        fetchTest();
                        fetchParts();
                    } else {
                        message.error(data.message || 'Kh├┤ng thß╗â duyß╗çt ─æß╗ü thi');
                    }
                } catch (error) {
                    message.error('C├│ lß╗ùi xß║úy ra khi duyß╗çt ─æß╗ü thi');
                } finally {
                    setApproving(false);
                }
            }
        });
    };

    const handleConfirmReject = async () => {
        if (!test || !rejectReason.trim()) {
            message.warning('Vui l├▓ng nhß║¡p l├╜ do tß╗½ chß╗æi');
            return;
        }

        setRejecting(true);
        try {
            const data = await testApi.reject(test.id, rejectReason);
            if (data.success) {
                message.success('─É├ú tß╗½ chß╗æi ─æß╗ü thi th├ánh c├┤ng');
                setIsRejectModalOpen(false);
                fetchTest();
                fetchParts();
            } else {
                message.error(data.message || 'Kh├┤ng thß╗â tß╗½ chß╗æi ─æß╗ü thi');
            }
        } catch (error) {
            message.error('C├│ lß╗ùi xß║úy ra khi tß╗½ chß╗æi ─æß╗ü thi');
        } finally {
            setRejecting(false);
        }
    };


    const handleDeletePart = async (partId: string, partNumber: number) => {
        Modal.confirm({
            title: 'X├íc nhß║¡n x├│a Part',
            content: (
                <div>
                    <p>Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a <strong>Part {partNumber}</strong>?</p>
                    <p style={{ color: '#DC2626', marginTop: 8 }}>
                        ΓÜá∩╕Å H├ánh ─æß╗Öng n├áy <strong>kh├┤ng thß╗â ho├án t├íc</strong>. To├án bß╗Ö c├óu hß╗Åi, ─æoß║ín v─ân v├á ├óm thanh trong Part n├áy sß║╜ bß╗ï x├│a v─⌐nh viß╗àn khß╗Åi Cloudinary v├á Database.
                    </p>
                </div>
            ),
            okText: 'X├│a v─⌐nh viß╗àn',
            okType: 'danger',
            cancelText: 'Hß╗ºy',
            onOk: async () => {
                try {
                    const data = await partApi.delete(partId);
                    if (data.success) {
                        message.success(`─É├ú x├│a Part ${partNumber} th├ánh c├┤ng!`);
                        fetchParts();
                    } else {
                        message.error(data.message || 'Kh├┤ng thß╗â x├│a Part');
                    }
                } catch (error) {
                    console.error('Error deleting part:', error);
                    message.error('C├│ lß╗ùi xß║úy ra khi x├│a Part');
                }
            },
        });
    };

    const columns: ColumnsType<Part> = [
        {
            title: 'Sß╗æ hiß╗çu',
            dataIndex: 'partNumber',
            key: 'partNumber',
            width: 120,
            align: 'center',
            render: (num) => (
                <div style={{
                    background: '#F1F5F9',
                    color: '#475569',
                    display: 'inline-block',
                    padding: '4px 12px',
                    borderRadius: '8px',
                    fontWeight: 600,
                    fontSize: '13px',
                    textAlign: 'center',
                    border: '1px solid #E2E8F0'
                }}>
                    PART {num}
                </div>
            ),
        },
        {
            title: 'T├¬n ph├ón ─æoß║ín',
            dataIndex: 'partName',
            key: 'partName',
            width: 250,
            align: 'center',
            render: (name) => (
                <div style={{ fontWeight: 600, color: '#1E3A8A', textAlign: 'center' }}>
                    {name.replace(/^Part \d+: /, '')}
                </div>
            ),
        },
        {
            title: 'Tß╗òng c├óu',
            dataIndex: 'totalQuestions',
            key: 'totalQuestions',
            width: 100,
            align: 'center',
            render: (total) => <span style={{ fontWeight: 600, color: '#64748B' }}>{total} c├óu</span>,
        },
        {
            title: 'Thß╗¥i gian',
            dataIndex: 'timeLimit',
            key: 'timeLimit',
            width: 140,
            align: 'center',
            render: (timeLimit) => {
                if (!timeLimit) return <Tag>Kh├┤ng giß╗¢i hß║ín</Tag>;
                const m = Math.floor(timeLimit / 60);
                const s = timeLimit % 60;
                return (
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6, fontWeight: 600, color: '#10B981' }}>
                        <ClockCircleOutlined style={{ fontSize: 13 }} />
                        {m}:{s.toString().padStart(2, '0')}
                    </div>
                );
            },
        },
        {
            title: 'Ho├án thiß╗çn',
            key: 'progress',
            width: 180,
            align: 'center',
            render: (_, record) => {
                const percent = Math.round((record.completedQuestions / record.totalQuestions) * 100);
                return (
                    <div style={{ padding: '0 8px' }}>
                        <Progress
                            percent={percent}
                            size="small"
                            strokeColor={{
                                '0%': '#3B82F6',
                                '100%': '#10B981',
                            }}
                            status={percent === 100 ? 'success' : 'active'}
                        />
                        <div style={{ fontSize: 11, color: '#94A3B8', marginTop: 2, fontWeight: 600 }}>
                            {record.completedQuestions} / {record.totalQuestions}
                        </div>
                    </div>
                );
            },
        },
        {
            title: 'H├ánh ─æß╗Öng',
            key: 'actions',
            width: 150,
            align: 'center',
            fixed: 'right',
            render: (_, record) => (
                <Space>
                    <Button
                        type="text"
                        style={{ color: '#3B82F6', background: '#EFF6FF', borderRadius: '8px' }}
                        icon={<EyeOutlined />}
                        onClick={() => handleViewDetails(record)}
                        title="Xem chi tiß║┐t"
                    />
                    {canManage && (
                        <Button
                            type="text"
                            style={{ color: '#059669', background: '#ECFDF5', borderRadius: '8px' }}
                            icon={<EditOutlined />}
                            onClick={() => handleEdit(record)}
                            title="Chß╗ënh sß╗¡a"
                        />
                    )}
                    {canManage && (
                        <Button
                            type="text"
                            style={{ color: '#DC2626', background: '#FEF2F2', borderRadius: '8px' }}
                            icon={<DeleteOutlined />}
                            onClick={() => handleDeletePart(record.id, record.partNumber)}
                            title="X├│a Part"
                        />
                    )}
                </Space>
            ),
        },
    ];

    const getDifficultyLabel = (difficulty: string) => {
        const map: any = {
            A1_A2: 'A1-A2',
            B1_B2: 'B1-B2',
            C1: 'C1',
        };
        return map[difficulty] || difficulty;
    };

    const renderInstructionsField = (isCreate: boolean) => {
        const content = isCreate ? createInstructions : editInstructions;
        const setContent = isCreate ? setCreateInstructions : setEditInstructions;

        return (
            <>
                <div style={{ marginBottom: 16 }}>
                    <p style={{ color: '#666', marginBottom: 8 }}>
                        Viß║┐t h╞░ß╗¢ng dß║½n cho hß╗ìc vi├¬n khi l├ám b├ái Part n├áy.
                        Bß║ín c├│ thß╗â ch├¿n ß║únh minh hß╗ìa trß╗▒c tiß║┐p v├áo nß╗Öi dung.
                    </p>
                </div>

                <InstructionEditor
                    value={content}
                    onChange={setContent}
                    placeholder="Nhß║¡p h╞░ß╗¢ng dß║½n cho Part n├áy..."
                />
            </>
        );
    };

    return (
        <div style={{ padding: '24px', background: '#F8FAFC', minHeight: '100vh' }}>
            {/* Header */}
            <div style={{ marginBottom: 24, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <Button
                    size="large"
                    icon={<ArrowLeftOutlined />}
                    onClick={() => navigate('/exam-bank')}
                    style={{ borderRadius: 12, fontWeight: 600, color: '#475569', display: 'flex', alignItems: 'center', gap: 8 }}
                >
                    Quay lß║íi danh s├ích
                </Button>

                <Space>
                    {isAdmin && (test?.status === 'PENDING' || test?.status === 'REJECTED') && (
                        <>
                            <Button
                                size="large"
                                type="primary"
                                icon={<CheckCircleOutlined />}
                                onClick={handleApproveTest}
                                loading={approving}
                                style={{ borderRadius: 12, fontWeight: 600, background: '#10B981', border: 'none' }}
                            >
                                Duyß╗çt to├án bß╗Ö
                            </Button>
                            <Button
                                size="large"
                                danger
                                icon={<EyeInvisibleOutlined />}
                                onClick={() => {
                                    setRejectReason('');
                                    setIsRejectModalOpen(true);
                                }}
                                style={{ borderRadius: 12, fontWeight: 600 }}
                            >
                                Tß╗½ chß╗æi
                            </Button>
                        </>
                    )}
                    {canManage && (
                        <Button
                            size="large"
                            danger
                            icon={<DeleteOutlined />}
                            onClick={handleDeleteTest}
                            style={{ borderRadius: 12, fontWeight: 600, display: 'flex', alignItems: 'center', gap: 8 }}
                        >
                            X├│a ─æß╗ü thi
                        </Button>
                    )}
                </Space>
            </div>

            {/* Cascading Approval Banner - REMOVED per CTO Pivot */}

            {test && (
                <Card
                    style={{
                        marginBottom: 32,
                        borderRadius: 24,
                        border: 'none',
                        boxShadow: modernShadow,
                        background: '#FFFFFF',
                        overflow: 'hidden'
                    }}
                    bodyStyle={{ padding: 0 }}
                >
                    <div style={{
                        background: 'linear-gradient(135deg, #1E3A8A 0%, #1D4ED8 100%)',
                        padding: '24px 32px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'space-between'
                    }}>
                        <Space size={16}>
                            <div style={{
                                width: 56,
                                height: 56,
                                borderRadius: 16,
                                background: 'rgba(255, 255, 255, 0.1)',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                color: '#FFF',
                                fontSize: 28,
                                border: '1px solid rgba(255, 255, 255, 0.2)',
                                backdropFilter: 'blur(4px)',
                            }}>
                                <FileTextOutlined />
                            </div>
                            <div>
                                <h2 style={{ margin: 0, color: '#FFFFFF', fontSize: 22, fontWeight: 700 }}>{test?.title}</h2>
                                <div style={{ color: 'rgba(255, 255, 255, 0.7)', fontSize: 14 }}>M├ú ─æß╗ü: {test?.id}</div>
                            </div>
                        </Space>
                        <div style={{
                            background: test?.status === 'ACTIVE' ? '#ECFDF5' : (test?.status === 'PENDING' ? '#FFFBEB' : '#FEF2F2'),
                            color: test?.status === 'ACTIVE' ? '#059669' : (test?.status === 'PENDING' ? '#D97706' : '#DC2626'),
                            padding: '4px 16px',
                            borderRadius: '30px',
                            fontWeight: 700,
                            fontSize: '13px',
                            boxShadow: '0 4px 10px rgba(0,0,0,0.1)',
                            display: 'flex',
                            alignItems: 'center',
                            gap: 6,
                            border: `1px solid currentColor`
                        }}>
                            {test?.status === 'ACTIVE' ? <UnlockOutlined /> : (test?.status === 'PENDING' ? <ClockCircleOutlined /> : (test?.status === 'REJECTED' ? <EyeInvisibleOutlined /> : <LockOutlined />))}
                            {test?.status === 'ACTIVE' ? '─ÉANG Mß╗₧' : (test?.status === 'PENDING' ? 'CHß╗£ DUYß╗åT' : (test?.status === 'REJECTED' ? 'Bß╗è Tß╗¬ CHß╗ÉI' : '─ÉANG KH├ôA'))}
                        </div>
                    </div>

                    {test?.status === 'REJECTED' && test.rejectReason && (
                        <div style={{
                            background: '#FEF2F2',
                            padding: '12px 32px',
                            borderBottom: '1px solid #FEE2E2',
                            color: '#991B1B',
